VkDevice device = VK_NULL_HANDLE;
VkDisplayKHR display = VK_NULL_HANDLE;
VkDisplayPowerInfoEXT displayPowerInfo = {};
displayPowerInfo.sType = VK_STRUCTURE_TYPE_DISPLAY_POWER_INFO_EXT;

VkResult result = vkDisplayPowerControlEXT(
 device,
 display,
 &displayPowerInfo
);

if (result == VK_SUCCESS) {
 // تمت العملية بنجاح ويمكن متابعة العمل بعد vkDisplayPowerControlEXT
} else {
 // عالج رمز الخطأ أو أعد تهيئة الموارد المطلوبة
}
